<template>
  <div class="input-container">
    <input
      v-model.number="inputValue"
      @input="handleInput"
      :style="{ width: inputWidth }"
      maxlength="5"
    />
  </div>
</template>

<script>
export default {
  props: {
    value: [String, Number],
    width: String,
  },
  data() {
    return {
      inputValue: null, // 初始化为 null
    };
  },
  computed: {
    inputWidth() {
      return this.width || "200px"; // 默认宽度
    },
  },
  methods: {
    handleInput() {
      // 限制输入最大值为 65535
      if (this.inputValue > 65535) {
        this.inputValue = 65535;
      }
      // 向父组件传递输入值，确保是数字类型
      this.$emit("update:port", Number(this.inputValue));
    },
  },
  watch: {
    value(newValue) {
      // 监听父组件传递的值变化
      this.inputValue = newValue;
    },
  },
  mounted() {
    // 在组件挂载时初始化 inputValue
    this.inputValue = this.value;
  },
};
</script>

<style scoped>
.input-container {
  margin-left: 5px;
  margin-right: 5px;
}

input {
  padding: 5px;
  border: 1px solid #ccc;
  border-radius: 4px;
}
</style>
