<template>
  <div class="ip-input">
    <div class="ip-section">
      <input id="ipSectionA" v-model="ipSections.a" @input="handleInput('a')" type="number" placeholder="000" :max="255" class="ip-input-field" />
      <label for="ipSectionA" class="ip-section-label">.</label>
    </div>
    <div class="ip-section">
      <input id="ipSectionB" v-model="ipSections.b" @input="handleInput('b')" type="number" placeholder="000" :max="255" class="ip-input-field" />
      <label for="ipSectionB" class="ip-section-label">.</label>
    </div>
    <div class="ip-section">
      <input id="ipSectionC" v-model="ipSections.c" @input="handleInput('c')" type="number" placeholder="000" :max="255" class="ip-input-field" />
      <label for="ipSectionC" class="ip-section-label">.</label>
    </div>
    <div class="ip-section">
      <input id="ipSectionD" v-model="ipSections.d" @input="handleInput('d')" type="number" placeholder="000" :max="255" class="ip-input-field" />
    </div>
  </div>
</template>

<script>
export default {
  name: 'IPInput',
  props: {
    initialIp: {
      type: [String, Number],
      default: '0.0.0.0',
    },
  },
  data() {
    return {
      ipSections: {
        a: "",
        b: "",
        c: "",
        d: "",
      },
    };
  },
  computed: {
    ipAddress() {
      return `${this.ipSections.a}.${this.ipSections.b}.${this.ipSections.c}.${this.ipSections.d}`;
    },
  },
  methods: {
    handleInput(section) {
      // 限制输入范围为 0 到 255
      this.ipSections[section] = Math.min(255, Math.max(0, this.ipSections[section]));
      this.$emit('update:ipAddress', this.ipAddress);
    },
  },
  mounted() {
    let ip = this.initialIp;
    if (typeof ip === 'string') {
      const sections = ip.split('.');
      if (sections.length === 4) {
        this.ipSections.a = sections[0];
        this.ipSections.b = sections[1];
        this.ipSections.c = sections[2];
        this.ipSections.d = sections[3];
      }
    }
    
  },
};
</script>

<style scoped>
.ip-input {
  display: flex;
  align-items: center;
  margin: 5px; /* 调整整体控件的外边距 */
}
.ip-section {
  display: flex;
  align-items: center;
  margin: 0 0px; /* 调整每个输入部分的外边距 */
}
.ip-section input {
  width: 60px; /* 调整输入框宽度，以确保可以完整显示三位数 */
  padding: 5px;
  border: 1px solid #ccc;
  border-radius: 4px;
}
.ip-section-label {
  margin: 0 1px;
}
</style>
