<script>
import in_put from "./in_put.vue"
import Card from "@/examples/Cards/Card.vue";
import RoundedVideo from "./linshi_img.vue";

export default {
  name: "controll_hand",
  mounted() {
	  var that=this
	  
	  that.$global_.x_force=0.0
	  that.$global_.y_force=0.0
	  
	 
	  that.intervalId = setInterval(() => {
	    that.update_ui();
	  }, 300);
  },
  data() {
    return {
		imagePath: require('@/assets/output.png'),
	text:"测量值超标",
	  showImage:false,
	  chart_flag:false,
	  chart_title:"yaw(°)",
	  chart_param:0,
	  chart_scol_len:50,
	  chart_update_time:50,
	  chart_update_data_time:500,
	  prefixTextFromParent: "左主推",
	  prefixTextFromParent1: "右主推",
	  receivedValue: 0,
	  x_force:0,
	  y_force:0,
	  inputText: "",
	  ph_test:7,
	  zhuodu_test:7,
	  ox_test:7,
	  elec_test:7,
	  temp_test:7,
	  Chlorophyll_test:7,
	  Phycocyanin_test:7,
	  yaw_test:60.0,
	  pitch_test:10.0,
	  roll_test:10.0,
	  pop_right_test:10.0,
	  pop_left_test:10.0,
	  lon_test:126.681632,
	  lat_test:45.776638,
	  show_warning:false,
	  warning_button:"打开警报",
      stats: {
        speed_u: {
          title: "PH值",
          value: "0.0",
          percentage: "浊度(NTU)",
          iconClass: "ni ni-user-run",
          iconBackground: "bg-gradient-danger",
          detail: "",
        },
        speed_v: {
          title: "氧溶解率",
          value: "0.0",
          percentage: "温度(℃)",
          iconClass: "ni ni-user-run",
          iconBackground: "bg-gradient-danger",
          detail: "",
        },
        speed_w: {
          title: "电导率",
          value: "0.0",
          percentage: "藻蓝蛋白",
          iconClass: "ni ni-user-run",
          iconBackground: "bg-gradient-danger",
          detail: "",
        },
		speed_yaw: {
		  title: "艏向角(°/s)",
		  value: "0.0",
		  percentage: "叶绿素含量",
		  iconClass: "ni ni-planet",
		  iconBackground: "bg-info",
		  detail: "0.0",
		},
		speed_pitch: {
		  title: "纵倾角(°/s)",
		  value: "0.0",
		  percentage: "左推进器电压",
		  iconClass: "ni ni-planet",
		  iconBackground: "bg-info",
		  detail: "0.0",
		},
		speed_roll: {
		  title: "横滚角(°/s)",
		  value: "0.0",
		  percentage: "右推进器电压",
		  iconClass: "ni ni-planet",
		  iconBackground: "bg-info",
		  detail: '0.0',
		},
		lon: {
		  title: "经度(°)",
		  value: "0.0",
		  percentage: "",
		  iconClass: "ni ni-world",
		  iconBackground: "bg-default",
		  detail: "",
		},
		lat: {
		  title: "纬度(°)",
		  value: "0.0",
		  percentage: "",
		  iconClass: "ni ni-world",
		  iconBackground: "bg-default",
		  detail: "",
		},
      },
    };
  },
  components: {
    Card,
	in_put,
	RoundedVideo
  },
  methods: {
	onItemSelected(item) {
	var that=this
	  that.$global_.map_flag=item.index;
	  // 处理选中项的逻辑
	},
	
	onItemSelected1(item) {
		var that=this
		that.$global_.communication_flag=item.index;
	  // 处理选中项的逻辑
	},
		
	
	
	handleChildInput(valueFromChild) {
	var that=this
	  // 从子组件接收值，并在父组件中处理
	  that.x_force = valueFromChild;
	},
	handleChildInput1(valueFromChild) {
	var that=this
	  // 从子组件接收值，并在父组件中处理
	  that.y_force = valueFromChild;
	},
	
	
	
	handleButtonClick()
	{
		var that=this
		that.$global_.x_force       =that.x_force;       
		that.$global_.y_force       =that.y_force;        
	},
	
	handleButtonClick1()
	{
		var that=this
		that.show_warning=!that.show_warning       
	},
	
	random(min, max) {
	  if (min > max) {
		console.error("最小值不能大于最大值");
		return null;
	  }
	  // 生成随机值并保留两位小数
	  return parseFloat((Math.random() * (max - min) + min).toFixed(2));
	},
	
	randomgps(min, max) {
	  if (min > max) {
		console.error("最小值不能大于最大值");
		return null;
	  }
	  // 生成随机值并保留两位小数
	  return parseFloat((Math.random() * (max - min) + min).toFixed(5));
	},
	
	update_ui(){
		var that=this
		if(that.show_warning)
		{
			
			
			if (that.$global_.PH<5.5||that.$global_.PH>9.5
			||that.$global_.zhuodu>32.1||that.$global_.elec>770
			||that.$global_.o2<1.1) {
				that.showImage=true
			}else{
				that.showImage=false
			}
			that.warning_button="关闭警报"
		}else{
			that.warning_button="打开警报"
			that.showImage=false
		}
		
		
		
		that.$global_.map_markers=[]
		that.stats.speed_u.value=that.$global_.PH.toFixed(2).toString()
		that.stats.speed_u.detail=that.$global_.zhuodu.toFixed(2).toString()
		
		that.stats.speed_v.value=that.$global_.o2.toFixed(2).toString()
		that.stats.speed_v.detail=that.$global_.Temp.toFixed(2).toString()
		
		that.stats.speed_w.value=that.$global_.elec.toFixed(2).toString()
		that.stats.speed_w.detail=that.$global_.zaolandanbai.toFixed(2).toString()
		
		that.stats.speed_yaw.value=that.$global_.lower_yaw.toFixed(3).toString()
		that.stats.speed_yaw.detail=that.$global_.yelvsu.toFixed(2).toString()
		
		that.stats.speed_pitch.value=that.$global_.lower_pitch.toFixed(3).toString()
		that.stats.speed_pitch.detail=that.$global_.lower_y_force.toFixed(2).toString()//左推进器
		
		that.stats.speed_roll.value=that.$global_.lower_roll.toFixed(3).toString()
		that.stats.speed_roll.detail=that.$global_.lower_x_force.toFixed(2).toString()//右推进器
		
		that.stats.lon.value=that.$global_.lower_lon.toFixed(5).toString()
		that.stats.lat.value=that.$global_.lower_lat.toFixed(5).toString()
		
		
	},
	clearTimer() {
		// 清除定时器
		var that=this
		clearInterval(that.intervalId);
	},
  },
  beforeUnmount() {
	  var that=this
      that.clearTimer();
  },
};
</script>

