<template>
  <div class="table-container">
    <div class="table-header">
      <table class="header-table">
        <thead>
          <tr>
            <th>经度</th>
            <th>纬度</th>
          </tr>
        </thead>
      </table>
    </div>
    <div class="table-body">
      <table class="data-table">
        <tbody>
          <tr v-for="(coord, index) in coordinates" :key="index" @click="selectCoordinate(index)" :class="{ 'selected': selectedIndex === index }">
            <td>
              <span v-if="!isAdjusting || selectedIndex !== index">{{ coord.longitude }}</span>
              <input v-else type="number" v-model="adjustedLongitude" @input="updateAdjustedCoordinate('longitude', adjustedLongitude)" />
            </td>
            <td>
              <span v-if="!isAdjusting || selectedIndex !== index">{{ coord.latitude }}</span>
              <input v-else type="number" v-model="adjustedLatitude" @input="updateAdjustedCoordinate('latitude', adjustedLatitude)" />
            </td>
          </tr>
        </tbody>
      </table>
    </div>
  </div>
  <div class="button-container">
    <button @click="addCoordinate" class="custom-button">添加</button>
    <button @click="removeCoordinate" class="custom-button">删除</button>
    <button @click="toggleAdjustMode" class="custom-button">{{ isAdjusting ? '保存' : '调整' }}</button>
  </div>
</template>

<script>
export default {
  props: {
    coordinates: Array,
	flag: Boolean,
  },
  data() {
    return {
      selectedIndex: -1,
      isAdjusting: false,
      adjustedLongitude: 0,
      adjustedLatitude: 0,
    };
  },
  watch: {
      flag(newVal) {
        if (newVal&&this.selectedIndex>=0) {
          this.adjustedLongitude = this.coordinates[this.selectedIndex].longitude;
          this.adjustedLatitude = this.coordinates[this.selectedIndex].latitude;
          this.$emit('update-flag', false); // Reset flag after updating
        }
      },
    },
  methods: {
	
    addCoordinate() {
      const newCoordinate = { longitude: 0, latitude: 0 };
      this.$emit("add-coordinate", newCoordinate);
    },
    removeCoordinate() {
      if (this.selectedIndex !== -1) {
        this.$emit("remove-coordinate", this.selectedIndex);
      }
    },
    selectCoordinate(index) {
      this.selectedIndex = index;
      this.adjustedLongitude = this.coordinates[index].longitude;
      this.adjustedLatitude = this.coordinates[index].latitude;
	  this.$emit("select-coordinate", index);
    },
    toggleAdjustMode() {
      if (this.isAdjusting) {
        this.$emit("save-adjusted-coordinates", this.coordinates);
      }
      this.isAdjusting = !this.isAdjusting;
	  this.$emit("change-mode", this.isAdjusting);
    },
    updateAdjustedCoordinate(property, value) {
      if (this.selectedIndex !== -1) {
        this.$emit("adjust-coordinate", {
          index: this.selectedIndex,
          property,
          value: parseFloat(value),
        });
      }
    },
  },
};
</script>

