<template>
  <div class="rounded-video-wrapper" :style="{ padding: padding }">
    <div 
      class="rounded-video-container" 
      :style="{
        borderRadius: radius,
        boxShadow: shadow,
        width: width,
        height: height,
        maxWidth: maxWidth
      }"
    >
      <video 
        ref="video"
        class="rounded-video"
        :style="{ borderRadius: radius }"
        @error="handleVideoError"
        controls
        autoplay
        loop
      >
        <p>{{ errorText }}</p>
      </video>
      <div v-if="isError" class="error-placeholder">
        {{ errorText }}
      </div>
    </div>
  </div>
</template>

<script>
import Hls from "hls.js";

export default {
  name: "RoundedVideo",
  props: {
    src: {
      type: String,
      required: true
    },
    radius: {
      type: String,
      default: "8px"
    },
    shadow: {
      type: String,
      default: "0 4px 12px rgba(0, 0, 0, 0.15)"
    },
    width: {
      type: String,
      default: "100%"
    },
    height: {
      type: String,
      default: "auto"
    },
    maxWidth: {
      type: String,
      default: "100%"
    },
    errorText: {
      type: String,
      default: "视频加载失败"
    },
    padding: {
      type: String,
      default: "10px 20px"
    }
  },
  data() {
    return {
      isError: false
    };
  },
  mounted() {
    this.$nextTick(() => {
      this.setupVideo();
    });
  },
  watch: {
    src: {
      immediate: true,
      handler() {
        this.$nextTick(() => {
          this.setupVideo();
        });
      }
    }
  },
  methods: {
    setupVideo() {
      const video = this.$refs.video;
      if (!video) {
        console.error("Video element is not available yet.");
        return;
      }

      if (video.canPlayType("application/vnd.apple.mpegurl")) {
        video.src = this.src;
      } else if (Hls.isSupported()) {
        const hls = new Hls();
        hls.loadSource(this.src);
        hls.attachMedia(video);
        hls.on(Hls.Events.ERROR, (event, data) => {
          console.error("HLS播放错误:", data);
          this.isError = true;
        });
      } else {
        console.error("当前浏览器不支持HLS");
        this.isError = true;
      }
    },
    handleVideoError() {
      this.isError = true;
    }
  }
};
</script>

<style scoped>
.rounded-video-wrapper {
  display: inline-block;
  box-sizing: border-box;
}

.rounded-video-container {
  position: relative;
  overflow: hidden;
  display: inline-block;
  background-color: #f5f5f5;
}

.rounded-video {
  display: block;
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: transform 0.3s ease;
}

.rounded-video:hover {
  transform: scale(1.03);
}

.error-placeholder {
  position: absolute;
  top: 0;
  left: 0;
  width: 100%;
  height: 100%;
  display: flex;
  align-items: center;
  justify-content: center;
  color: #999;
  background-color: #eee;
  font-size: 14px;
}
</style>
