<template>
  <div style="display: none;"></div>
</template>

<script>
import { ref, onMounted, onUnmounted } from "vue";

export default {
  name: "GamepadHandler",
  emits: ["input"], // 用于向父组件发送手柄输入事件
  setup(_, { emit }) {
    const gamepads = ref([]);
    let intervalId = null; // 用于存储 setInterval 的 ID

    // 更新手柄状态
    const updateGamepads = () => {
      const connectedGamepads = navigator.getGamepads
        ? Array.from(navigator.getGamepads()).filter((gp) => gp)
        : [];
      gamepads.value = connectedGamepads;

      // 遍历所有连接的手柄
      connectedGamepads.forEach((gamepad) => {
        if (gamepad) {
          // const buttons = gamepad.buttons.map((button) => button.pressed);
          const axes = gamepad.axes;

          // 向父组件发送手柄输入事件
          emit("input", { axes });
        }
      });
    };

    // 监听手柄连接事件
    const onGamepadConnected = (event) => {
      console.log("Gamepad connected:", event.gamepad);
    };

    // 监听手柄断开事件
    const onGamepadDisconnected = (event) => {
      console.log("Gamepad disconnected:", event.gamepad);
    };

    onMounted(() => {
      window.addEventListener("gamepadconnected", onGamepadConnected);
      window.addEventListener("gamepaddisconnected", onGamepadDisconnected);

      // 使用 setInterval 每 10 毫秒更新一次
      intervalId = setInterval(updateGamepads, 10);
    });

    onUnmounted(() => {
      window.removeEventListener("gamepadconnected", onGamepadConnected);
      window.removeEventListener("gamepaddisconnected", onGamepadDisconnected);

      // 清除定时器
      if (intervalId) {
        clearInterval(intervalId);
      }
    });

    return {
      gamepads,
    };
  },
};
</script>
