<template>
  <div>
  </div>
</template>

<script>
	
export default {
  data() {
    return {
      socket: null,
      message: "",
      receivedMessages: "",
      intervalId: null, // Timer ID for sending messages every 1 second
    };
  },
  mounted() {
    // Connect to WebSocket server
    this.socket = new WebSocket("ws://localhost:8080/servers/ws");

    // // Set up event listeners
    this.socket.addEventListener("open", () => {
      console.log("WebSocket connection opened");
    });

    this.socket.addEventListener("message", (event) => {
      // Handle received messages
      this.receivedMessages=event.data;
    });

    this.socket.addEventListener("close", () => {
      console.log("WebSocket connection closed");
    });

    // Use setInterval to send messages every 1 second
    this.intervalId = setInterval(() => {
      this.sendMessage();
    }, 300);
  },
  methods: {
    sendMessage() {
		
		this.parseReceivedMessage(this.receivedMessages)
		var jsonMessage = {
		  mode: this.$global_.mode,
		};
		if (this.$global_.mode==0||this.$global_.mode==1||this.$global_.mode==2||this.$global_.mode==3||this.$global_.mode==4||this.$global_.mode==5) {
			jsonMessage = {
			  mode: this.$global_.mode,
			  x_force:this.$global_.x_force,
			  y_force:this.$global_.y_force,
			  z_force:this.$global_.z_force,
			  yaw_force:this.$global_.yaw_force,
			  pitch_force:this.$global_.pitch_force,
			  roll_force:this.$global_.roll_force,
			  exp_x_v:this.$global_.exp_x_v,
			  exp_y_v:this.$global_.exp_y_v,
			  exp_depth:this.$global_.exp_depth,
			  exp_yaw:this.$global_.exp_yaw,
			  exp_pitch:this.$global_.exp_pitch,
			  exp_roll:this.$global_.exp_roll,
			  time_protect:this.$global_.time_protect,
			  depth_protect:this.$global_.depth_protect,
			  height_protect:this.$global_.height_protect,
			  point_count:this.$global_.point_count,
			  points:this.$global_.points,
			};
		}
		else if (this.$global_.mode==5) {
			jsonMessage = {
			  mode: this.$global_.mode,
			};
		}else if (this.$global_.mode==6) {
			jsonMessage = {
			  mode: this.$global_.mode,
			};
		}else if (this.$global_.mode==7) {
			jsonMessage = {
			  mode: this.$global_.mode,
			  forward_sonar_switch: this.$global_.switchstatus_forward_sonar,
			  forward_sonar_cpu_switch: this.$global_.switchstatus_forward_sonar_cpu,
			  sidescan_sonar_switch: this.$global_.switchstatus_side_scan_sonar,
			  sidescan_sonar_cpu_switch: this.$global_.switchstatus_side_scan_sonar_cpu,
			  camera_switch: this.$global_.switchstatus_camera,
			  usbl_switch: this.$global_.switchstatus_usbl,
			  beiyong_24v: this.$global_.switchstatus_24v,
			  pc104_switch: this.$global_.switchstatus_pc104,
			  imu_switch: this.$global_.switchstatus_imu,
			  dvl_switch: this.$global_.switchstatus_dvl,
			  power_switch: this.$global_.switchstatus_power,
			  rudder_switch: this.$global_.switchstatus_rudder,
			  light_switch: this.$global_.switchstatus_light,
			  propeller_switch: this.$global_.switchstatus_propeller,
			  tcp_ip:this.$global_.tcp_ip,
			  tcp_port:this.$global_.tcp_port,
			  udp_ip:this.$global_.udp_ip,
			  udp_port_local:this.$global_.udp_local_port,
			  udp_port_target:this.$global_.udp_target_port,
			  com_fresh_flag:this.$global_.com_fresh_flag,
			  com_port:this.$global_.com_port,
			  com_BaudRate:this.$global_.com_rate,
			  tcp_connection_flag:this.$global_.tcp_connection_flag,
			  udp_connection_flag:this.$global_.udp_connection_flag,
			  com_connection_flag:this.$global_.com_connection_flag,
			  communication_mode:this.$global_.communication_mode
			};
			
		}
      

      // Send JSON message to the WebSocket server
		if (this.socket && this.socket.readyState === WebSocket.OPEN) {
			this.socket.send(JSON.stringify(jsonMessage));
			this.message = ""; // Clear input after sending
		} else {
			console.error("WebSocket connection not open");
		}
	  
    },
	parseReceivedMessage(data) {
		var that=this
		try {
			const parsed = JSON.parse(data);
			that.$global_.lower_x_speed = parsed.v_x || 0.0
			that.$global_.lower_y_speed = parsed.v_y || 0.0
			that.$global_.lower_z_speed = parsed.v_z || 0.0
			that.$global_.lower_yaw = parsed.yaw || 0.0
			that.$global_.lower_pitch = parsed.pitch || 0.0
			that.$global_.lower_roll = parsed.roll || 0.0
			that.$global_.lower_depth = parsed.depth || 0.0
			that.$global_.lower_height = parsed.height || 0.0
			that.$global_.lower_timer_protect = parsed.time || 0.0
			that.$global_.lower_lat = parsed.lat || 0.0
			that.$global_.lower_lon = parsed.lon || 0.0
			// that.$global_.communication_mode = parsed.communication_mode || 0
			that.$global_.plan_flag = parsed.plan_flag || 0
			var mid_con_list=[]
			for (var i=0;i<parsed.com_list.length;i++) {
				var obj={"text":parsed.com_list[i],"index":i}
				mid_con_list.push(obj)
			}
			that.$global_.lower_com_list = mid_con_list
			that.$global_.lower_z_force = parsed.f_z || 0.0
			that.$global_.lower_r_force = parsed.f_r || 0.0
			that.$global_.lower_x_force = parsed.f_x || 0.0
			that.$global_.lower_y_force = parsed.f_y || 0.0
			that.$global_.lower_p_force = parsed.f_p || 0.0
			that.$global_.lower_q_force = parsed.f_q || 0.0
			if (parsed.com_fresh_flag&&that.$global_.com_fresh_flag) {
				that.$global_.com_fresh_flag=false;
			}
			if (parsed.tcp_connection_flag&&that.$global_.tcp_connection_flag)
			{
				that.$global_.tcp_connection_flag=false
			}
			if (parsed.udp_connection_flag&&that.$global_.udp_connection_flag)
			{
				that.$global_.udp_connection_flag=false
			}
			if (parsed.com_connection_flag&&that.$global_.com_connection_flag)
			{
				that.$global_.com_connection_flag=false
			}
			that.$global_.tcp_connection_state=parsed.tcp_connection_state
			that.$global_.udp_connection_state=parsed.udp_connection_state
			that.$global_.com_connection_state=parsed.com_connection_state
			that.$global_.low_switchstatus_forward_sonar=parsed.switchstatus_forward_sonar
			that.$global_.low_switchstatus_forward_sonar_cpu=parsed.switchstatus_forward_sonar_cpu
			that.$global_.low_switchstatus_side_scan_sonar=parsed.switchstatus_side_scan_sonar
			that.$global_.low_switchstatus_side_scan_sonar_cpu=parsed.switchstatus_side_scan_sonar_cpu
			that.$global_.low_switchstatus_camera=parsed.switchstatus_camera
			that.$global_.low_switchstatus_usbl=parsed.switchstatus_usbl
			that.$global_.low_switchstatus_24v=parsed.switchstatus_24v
			that.$global_.low_switchstatus_power=parsed.switchstatus_power
			that.$global_.low_switchstatus_imu=parsed.switchstatus_imu
			that.$global_.low_switchstatus_dvl=parsed.switchstatus_dvl
			that.$global_.low_switchstatus_pc104=parsed.switchstatus_pc104
			that.$global_.low_switchstatus_rudder=parsed.switchstatus_rudder
			that.$global_.low_switchstatus_light=parsed.switchstatus_light
			that.$global_.low_switchstatus_propeller=parsed.switchstatus_propeller
			that.$global_.PH = parsed.ph
			that.$global_.Temp = parsed.temp
			that.$global_.elec = parsed.elec
			that.$global_.o2 = parsed.o2
			that.$global_.zhuodu = parsed.zhuodu
			that.$global_.zaolandanbai = parsed.zaolandanbai
			that.$global_.yelvsu = parsed.yelvsu
			// console.log(that.$global_.lower_x_force)
		} catch (error) {
			console.error("Failed to parse received message:", error);
		}
	},
  },
  beforeUnmount() {
    // Close WebSocket connection and clear the interval timer when the component is unmounted
    if (this.socket) {
      this.socket.close();
    }
    clearInterval(this.intervalId);
  },
};
</script>

