<template>
	<div class="card">
	   <div class="pb-0 card-header mb-0">
	      <h6>{{ title }}</h6>
	    </div>
	    <div class="p-3 card-body">
	      <div class="chart">
	        <canvas ref="myChart" class="chart-canvas" height="300"></canvas>
	      </div>
	    </div>
	  </div>
</template>

<script>
import Chart from "chart.js/auto";
import { markRaw } from 'vue'
export default {
	props: {
		title: {
			type: String,
			default: "yaw",
		},
		param:{
			type: Number,
			default: 0,
		},
		len:{
			type: Number,
			default: 0,
		},
		time:{
			type: Number,
			default: 0,
		},
		time_data:{
			type: Number,
			default: 0,
		}
	},
	data() {
		return{
			myChart:null,
			datasets:[],
			labels:[]
		}
	},
	
	beforeUnmount() {
		var that=this
		if (that.intervalId) {
			clearInterval(that.intervalId)
		}
		if (that.intervalId1) {
			clearInterval(that.intervalId1)
		}
		if (that.myChart) {
			that.myChart.destroy()
		}
	},
	mounted() {
		var that=this
		var ctx1 = this.$refs["myChart"].getContext("2d");
		var gradientStroke1 = ctx1.createLinearGradient(0, 230, 0, 50);
		gradientStroke1.addColorStop(1, "rgba(94, 114, 228, 0.2)");
		gradientStroke1.addColorStop(0.2, "rgba(94, 114, 228, 0.0)");
		gradientStroke1.addColorStop(0, "rgba(94, 114, 228, 0)");
		for (var i = 0; i < that.len; i++) {
			that.datasets.push(0)
			that.labels.push(i)
		}
		const myChart = new Chart(ctx1, {
		  type: "line",
		  data: {
			
			labels: that.labels,
			datasets: [
			  {
				label: that.title,
				tension: 0.4,
				borderWidth: 0,
				pointRadius: 0,
				borderColor: "#4BB543 ",
				backgroundColor: gradientStroke1,
				// eslint-disable-next-line no-dupe-keys
				borderWidth: 3,
				fill: true,
				data: that.datasets,
				maxBarThickness: 6,
			  },
			],
		  },
		  options: {
			responsive: true,
			maintainAspectRatio: false,
			plugins: {
			  legend: {
				display: false,
			  },
			},
			interaction: {
			  intersect: false,
			  mode: "index",
			},
			scales: {
			  y: {
				grid: {
				  drawBorder: false,
				  display: true,
				  drawOnChartArea: true,
				  drawTicks: false,
				  borderDash: [5, 5],
				},
				ticks: {
				  display: true,
				  padding: 10,
				  color: "#ccc",
				  font: {
					size: 11,
					family: "Open Sans",
					style: "normal",
					lineHeight: 2,
				  },
				},
			  },
			  x: {
				grid: {
				  drawBorder: false,
				  display: false,
				  drawOnChartArea: false,
				  drawTicks: false,
				  borderDash: [5, 5],
				},
				ticks: {
				  display: true,
				  color: "#ccc",
				  padding: 20,
				  font: {
					size: 11,
					family: "Open Sans",
					style: "normal",
					lineHeight: 2,
				  },
				},
			  },
			},
		  },
		});
		that.myChart = markRaw(myChart)
		that.intervalId = setInterval(() => {
		  that.update_ui();
		}, that.time);
		that.intervalId1 = setInterval(() => {
		  that.update_data();
		}, that.time_data);
	},
	methods: {
		update_ui(){
			var that=this
			that.myChart.data.datasets[0].data = that.datasets;
			that.myChart.data.datasets[0].label = that.title
			that.myChart.update()
		},
		update_data()
		{
			var that=this
			const newDatasetData = [...that.datasets]
			newDatasetData.shift()
			newDatasetData.push(that.param)
			that.datasets=newDatasetData
		}
	},
}
</script>