<template>
<div id="container">
	
</div>
</template>
<script>
import AMapLoader from "@amap/amap-jsapi-loader";
import _ from 'lodash';
export default {
	
  name: "map_",
  
  
  
  data() {
    return {
		map: null,
		mapPoints: [],
		markerClusterer: [],
		re_map_flag:1,
		now_markers:[],
		now_points:[]
    };
  },
  mounted() {
      // 在组件挂载后获取地图 API Key
            // 在加载完成后初始化地图
		this.initwebMap();
		// this.initlocalMap();
		this.re_map_flag=this.$global_.map_flag
		this.intervalId = setInterval(() => {
		  this.map_update();
		}, 100);
    },
  methods: {
	  
	createObjectKey(obj) {
	    return `${obj.longitude},${obj.latitude}`;
	},
	
	arraysAreEqual(array1, array2) {
	    if (array1.length !== array2.length) {
	        return false;
	    }
	
	    const map = new Map();
	
	    // 遍历 array1 并增加计数
	    array1.forEach(item => {
	        const key = this.createObjectKey(item);
	        map.set(key, (map.get(key) || 0) + 1);
	    });
	
	    // 遍历 array2 并减少计数
	    for (let item of array2) {
	        const key = this.createObjectKey(item);
	        if (!map.has(key)) {
	            return false;
	        }
	        const count = map.get(key);
	        if (count === 1) {
	            map.delete(key);
	        } else {
	            map.set(key, count - 1);
	        }
	    }
	
	    // 如果 map 为空，则两个数组相等
	    return map.size === 0;
	},

	  
	deepEqual(obj1, obj2) {
		var that=this
	    if (obj1 === obj2) {
	        return true; // 判断引用相等
	    }
	    
	    if (typeof obj1 !== 'object' || obj1 === null || typeof obj2 !== 'object' || obj2 === null) {
	        return false; // 如果不是对象或者是 null，直接返回 false
	    }
	    
	    const keys1 = Object.keys(obj1);
	    const keys2 = Object.keys(obj2);
	    
	    if (keys1.length !== keys2.length) {
	        return false; // 键的数量不同，直接返回 false
	    }
	    
	    for (let key of keys1) {
	        if (!keys2.includes(key) || !that.deepEqual(obj1[key], obj2[key])) {
	            return false; // 如果键不存在或者值不相等，返回 false
	        }
	    }
	    
	    return true; // 所有键和值都相等，返回 true
	},
	arraysEqual(array1, array2) {
		var that=this
	    if (array1.length !== array2.length) {
	        return false; // 数组长度不同，直接返回 false
	    }
	    
	    for (let i = 0; i < array1.length; i++) {
	        if (!that.deepEqual(array1[i], array2[i])) {
	            return false; // 对象不相等，返回 false
	        }
	    }
	    
	    return true; // 所有对象都相等，返回 true
	},
	
	
	
	map_update() {
		var that = this
		if (that.re_map_flag!=that.$global_.map_flag) {
			if (that.$global_.map_flag==0) {
				that.initwebMap();
				that.re_map_flag=that.$global_.map_flag
			}else if (that.$global_.map_flag==1) {
				that.initlocalMap();
				that.re_map_flag=that.$global_.map_flag
			}
		}
		
		
		if (!that.arraysAreEqual(that.now_points, that.$global_.map_markers)) {
		
		    const oldMarkersMap = new Map();
		    const newMarkersMap = new Map();
		    const newMarkerPositions = new Set();
		
		    // 构建旧标记和新标记的映射
		    that.now_markers.forEach((marker, index) => {
		        const key = `${marker.getPosition().getLng()},${marker.getPosition().getLat()},${index}`;
		        oldMarkersMap.set(key, marker);
		    });
		
		    that.$global_.map_markers.forEach((position, index) => {
		        const key = `${position.longitude},${position.latitude},${index}`;
		        newMarkersMap.set(key, position);
		        newMarkerPositions.add(key);
		    });
		
		    // 找出需要移除的标记
		    const markersToRemove = [];
		    oldMarkersMap.forEach((marker, key) => {
		        if (!newMarkerPositions.has(key)) {
		            markersToRemove.push(marker);
		        }
		    });
		
		    // 移除旧的标记
		    markersToRemove.forEach(marker => {
		        marker.setMap(null);
		    });
		
		    // 更新 now_markers
		    const updatedMarkers = [];
		    newMarkersMap.forEach((position, key) => {
		        const [longitude, latitude] = key.split(',');
		        const existingMarker = oldMarkersMap.get(key);
		        if (existingMarker) {
		            updatedMarkers.push(existingMarker);
		        } else {
		            const marker = new window.AMap.Marker({
		                position: new window.AMap.LngLat(parseFloat(longitude), parseFloat(latitude)), // 标记位置
		                map: that.map, // 将标记添加到地图实例
		                zIndex: 100 // 确保标记在折线之上
		            });
		
		            // 添加点击事件监听器
		            marker.on('click', () => {
		                that.$global_.map_click_flag = true;
		                that.$global_.map_select_point.lon = parseFloat(longitude);
		                that.$global_.map_select_point.lat = parseFloat(latitude);
		                console.log("that.$global_.map_select_point.lon", that.$global_.map_select_point.lon);
		                console.log("that.$global_.map_select_point.lat", that.$global_.map_select_point.lat);
		                console.log(`Marker clicked: Lon=${longitude}, Lat=${latitude}`);
		            });
		
		            updatedMarkers.push(marker);
		        }
		    });
		    that.now_markers = updatedMarkers;
		
		    // 移除旧的折线
		    if (that.polyline) {
		        that.polyline.setMap(null);
		    }
		
		    // 画线连接标记
		    if (that.now_markers.length > 1) { // 需要至少两个标记来画线
		        const linePath = that.now_markers.map(marker => marker.getPosition());
		        that.polyline = new window.AMap.Polyline({
		            path: linePath,
		            strokeColor: "rgba(51, 102, 255, 0.5)", // 线颜色，带透明度
		            strokeWeight: 1, // 线宽
		            zIndex: 1, // 确保折线在标记之下
		            map: that.map // 将折线添加到地图实例
		        });
		    }
		}

		that.now_points=_.cloneDeep(that.$global_.map_markers)
	},
	
	
	initlocalMap() {
		var that=this;
		const script_local = document.createElement('script');
		script_local.src = './amap/AMap3.js';
		
		script_local.onload=function()
		{
			const base_url = "http://localhost/map"
			const layers = [new window.AMap.TileLayer({
			    getTileUrl: function (x, y, z) {
			        return `${base_url}/${z}/${x}/${y}.png`;
			    },
			    opacity: 1,
			    zIndex: 99,
			})]
			that.map = new window.AMap.Map('container', { // 设置地图容器id
				resizeEnable: true,
				rotateEnable:true,
				pitchEnable:true,
				pitch: 90,
				zoom: 17,
				viewMode:'3D',//开启3D视图,默认为关闭
				expandZoomRange:true,
				zooms:[3,20],
				center:[that.$global_.lower_lon, that.$global_.lower_lat ],
				layers:layers
			})
			
			that.map.plugin(["AMap.ControlBar"], () => {
			   var controlBar = new window.AMap.ControlBar({
				   showZoomBar: true, //是否显示缩放按钮
				   showControlButton: true ,//是否显示倾斜、旋转按钮
				   position: { top: "155px", right: "37px" },
			   });
			   that.map.addControl(controlBar);
			});
			
			that.map.on('click', e => {
				that.$global_.map_click_flag=true
				console.log(that.$global_.map_click_flag)
				console.log(e.lnglat) // 获取鼠标点击位置的经纬度坐标
				console.log(e.lnglat.lng) // 获取鼠标点击位置的经纬度坐标
				console.log(e.lnglat.lat) // 获取鼠标点击位置的经纬度坐标
				that.$global_.map_select_point.lon=e.lnglat.lng
				that.$global_.map_select_point.lat=e.lnglat.lat
			})
		}
		
		if (!document.head.contains(script_local)) {
			document.head.appendChild(script_local);
		}
	},
	
	create_web_map()
	{
		var that=this
		  AMapLoader.load({
		      key: "7685a1a0cc9110f30a6262e79ea8061f", // 申请好的Web端开发者Key，首次调用 load 时必填
		      version: "2.0.1", // 指定要加载的 JSAPI 的版本，缺省时默认为 1.4.15
		      plugins: ["AMap.ToolBar", "AMap.Scale", "AMap.OverView", "AMap.MapType", "AMap.Geolocation", "AMap.AdvancedInfoWindow", "AMap.Autocomplete", "AMap.PlaceSearch", "AMap.DistrictSearch", "AMap.LineSearch", "AMap.StationSearch", "AMap.Driving", "AMap.TruckDriving", "AMap.Transfer", "AMap.Walking", "AMap.Riding", "AMap.DragRoute", "AMap.ArrivalRange", "AMap.Geocoder", "AMap.CitySearch", "AMap.CustomLayer", "AMap.ElasticMarker", "AMap.ControlBar", "AMap.PolylineEditor", "AMap.PolygonEditor", "AMap.RectangleEditor", "AMap.CircleEditor", "AMap.BezierCurveEditor", "AMap.MouseTool", "AMap.RangingTool"],
		  })
		  .then((AMap) => {
		    that.map = new AMap.Map("container", {
		  	// 设置地图容器id
		  	resizeEnable: true,
		  	rotateEnable:true,
		  	pitchEnable:true,
			pitch: 90,
		  	zoom: 17,
		  	viewMode:'3D',//开启3D视图,默认为关闭
		  	expandZoomRange:true,
		  	zooms:[3,20],
		  	center:[that.$global_.lower_lon, that.$global_.lower_lat],
		    });
			that.map.plugin(["AMap.ControlBar"], () => {
			   var controlBar = new window.AMap.ControlBar({
				   showZoomBar: true, //是否显示缩放按钮
				   showControlButton: true ,//是否显示倾斜、旋转按钮
				   position: { top: "155px", right: "37px" },
			   });
			   that.map.addControl(controlBar);
			});
			that.map.on('click', e => {
				var that=this
				that.$global_.map_click_flag=true
				console.log(that.$global_.map_click_flag)
				console.log(e.lnglat) // 获取鼠标点击位置的经纬度坐标
				console.log(e.lnglat.lng) // 获取鼠标点击位置的经纬度坐标
				console.log(e.lnglat.lat) // 获取鼠标点击位置的经纬度坐标
				that.$global_.map_select_point.lon=e.lnglat.lng
				that.$global_.map_select_point.lat=e.lnglat.lat
			})
		  })
		  .catch((e) => {
		    console.log(e);
		  });
	},
	
	initwebMap()
	{
		var that=this;
		const script_local = document.createElement('script');
		script_local.src = './amap/AMap3.js';
		if (document.head.contains(script_local)) {
			removeScript(script_local).then(() => {
			that.create_web_map();
			})
			.catch(error => {
				console.error('Error removing script element:', error);
			})		
		}else{
			this.create_web_map();
		}
	},
  },
  
  
  
  
  
  components: {
	  
  },
};

function removeScript(scriptElement) {
    return new Promise((resolve, reject) => {
      if (scriptElement.parentNode) {
        scriptElement.parentNode.removeChild(scriptElement);
        resolve();
      } else {
        reject(new Error('Script element is not in the document.'));
      }
    });
}
</script>
<style lang="scss">
#container {
  height: 100vh;
  width: 100vw;
}


</style>