<script>
import SidenavItem from "./SidenavItem.vue";

export default {
  name: "SidenavList",
  props: {
    cardBg: String
  },
  data() {
    return {
      title: "Argon Dashboard 2",
      controls: "dashboardsExamples",
      isActive: "active",
    };
  },
  components: {
    SidenavItem,
  },
  methods: {
    getRoute() {
      const routeArr = this.$route.path.split("/");
	  
	  
	  switch (routeArr[1]){
	  	case 'controll_hand':
			this.$global_.mode=0;
	  		break;
		case 'point':
			this.$global_.mode=3;
			break;
		case 'line':
			this.$global_.mode=4;
			break;
		case 'remote':
			console.log("sss");
			console.log(this.$route.path);
			this.$global_.mode=5;
			break;
		case 'brake':
			this.$global_.mode=6;
			break;
		case 'switch_cfg':
			this.$global_.mode=7;
			break;
	  	default:
	  		break;
	  }
      return routeArr[1];
	  
    }
  }
};
</script>

