<template>
  <div class="custom-dropdown" :style="dropdownStyles" ref="dropdown">
    <button class="btn btn-secondary dropdown-toggle" type="button" @click="toggleDropdown" :class="{ 'show': isOpen }">
      {{ selectedItem ? selectedItem.text : placeholder }}
    </button>
    <transition name="fade">
      <ul v-show="isOpen" class="custom-dropdown-menu" aria-labelledby="dropdownMenuButton" :style="{ maxHeight: dropdownHeight }">
        <li v-for="(item, index) in items" :key="index" @click="selectItem(item)">
          {{ item.text }}
        </li>
      </ul>
    </transition>
  </div>
</template>

<script>
export default {
  data() {
    return {
      isOpen: false,
      selectedItem: null,
      items: [],
    };
  },
  props: {
    placeholder: {
      type: String,
      default: 'Select an item',
    },
    initialSelectedItem: {
      type: Object,
      default: null,
    },
    customItems: {
      type: Array,
      default: () => [],
    },
    dropdownWidth: {
      type: String,
      default: '200px',
    },
    dropdownHeight: {
      type: String,
      default: '200px',
    },
    marginTop: {
      type: String,
      default: '0px',
    },
    marginBottom: {
      type: String,
      default: '0px',
    },
    marginLeft: {
      type: String,
      default: '0px',
    },
    marginRight: {
      type: String,
      default: '0px',
    },
  },
  watch: {
    initialSelectedItem: {
      handler(newValue) {
        this.selectedItem = newValue;
      },
      immediate: true,
    },
    customItems: {
      handler(newItems) {
        this.items = newItems;
      },
      immediate: true,
    },
  },
  computed: {
    dropdownStyles() {
      return {
        width: this.dropdownWidth,
        marginTop: this.marginTop,
        marginBottom: this.marginBottom,
        marginLeft: this.marginLeft,
        marginRight: this.marginRight,
      };
    },
  },
  methods: {
    toggleDropdown() {
      this.$nextTick(() => {
        this.isOpen = !this.isOpen;
      });
    },
    selectItem(item) {
      this.selectedItem = item;
      this.isOpen = false;
      this.$emit('item-selected', item);
    },
    handleClickOutside(event) {
      if (this.isOpen && !this.$refs.dropdown.contains(event.target)) {
        this.isOpen = false;
      }
    },
  },
  mounted() {
    document.addEventListener('click', this.handleClickOutside);
  },
  beforeUnmount() {
    document.removeEventListener('click', this.handleClickOutside);
  },
};
</script>

