<template>
  <div>
    <label :for="inputId" class="prefix-label">{{ prefixText }}</label>
    <input
      :id="inputId"
      v-model="formattedValue"
      @input="handleInput"
      class="custom-input"
    />
  </div>
</template>

<script>
export default {
  props: {
    prefixText: {
      type: String,
      default: "",
    },
    inputId: {
      type: String,
      default: "custom-input",
    },
  },
  data() {
    return {
      formattedValue: "",
      reFormattedValue: "",
    };
  },
  methods: {
    countCharacter(inputString, targetCharacter) {
      let characterCount = 0;

      for (let i = 0; i < inputString.length; i++) {
        if (inputString[i] === targetCharacter) {
          characterCount++;
        }
      }

      return characterCount;
    },
    handleInput() {
      const regex = /^-?\d*\.?\d*$/;
      const inputText = this.formattedValue;

      if (regex.test(inputText)) {
        const parsedValue = parseFloat(inputText);
        this.$emit("child-input", isNaN(parsedValue) ? 0 : parsedValue);
        this.reFormattedValue = this.formattedValue;
      } else {
        const sanitizedInput = inputText.replace(/[^-.\d]/g, "");
        this.formattedValue = sanitizedInput.startsWith('-') ? this.reFormattedValue : sanitizedInput;

        if (this.countCharacter(sanitizedInput, ".") > 1) {
          this.formattedValue = this.reFormattedValue;
        }
      }
    },
  },
};
</script>

