import { createRouter, createWebHistory } from "vue-router";
import controll_hand from "../views/controll_hand.vue";
import brake from "../views/brake.vue";
import point from "../views/point.vue";
import loading from "../views/loading.vue"
import map_ from "../views/map_.vue";
import switch_cfg from "../views/switch_cfg.vue";
import websocket_control from "../views/websocket_control.vue";
import remote from "../views/remote.vue";

const routes = [
	{
	  path: "/remote",
	  name: "remote",
	  component: remote,
	},
 
  {
    path: "/controll_hand",
    name: "controll_hand",
    component: controll_hand,
  },
  
  {
    path: "/websocket_control",
    name: "websocket_control",
    component: websocket_control,
  },
  {
    path: "/brake",
    name: "brake",
    component: brake,
  },
  {
    path: "/point",
    name: "point",
    component: point,
  },
  {
    path: "/loading",
    name: "loading",
    component: loading,
  },
  {
    path: "/map_",
    name: "map_",
    component: map_,
  },
  {
    path: "/switch_cfg",
    name: "switch_cfg",
    component: switch_cfg,
  },
];

const router = createRouter({
  history: createWebHistory(process.env.BASE_URL),
  routes,
  linkActiveClass: "active",
});

export default router;
